using Microsoft.AspNetCore.Components.Web;

namespace UnitTest.Components;

public class DynamicElementTest
{
    [Fact]
    public void Key_OK()
    {
        var context = new BunitContext();
        var cut = context.Render<DynamicElement>(pb =>
        {
            pb.Add(s => s.Key, Guid.NewGuid());
        });

        Assert.Equal("<div></div>", cut.Markup);
    }

    [Fact]
    public void OnTouchStart_Ok()
    {
        var context = new BunitContext();
        var triggered = false;

        var cut = context.Render<DynamicElement>(pb =>
        {
            pb.Add(s => s.OnTouchStart, (e) =>
            {
                triggered = true;
                return Task.CompletedTask;
            });
            pb.Add(s => s.TriggerTouchStart, true);
        });

        cut.InvokeAsync(() => cut.Find("div").TouchStart());
        Assert.True(triggered);
    }

    [Fact]
    public void OnTouchEnd_Ok()
    {
        var context = new BunitContext();
        var triggered = false;

        var cut = context.Render<DynamicElement>(pb =>
        {
            pb.Add(s => s.OnTouchEnd, (e) =>
            {
                triggered = true;
                return Task.CompletedTask;
            });
            pb.Add(s => s.TriggerTouchEnd, true);
        });

        cut.InvokeAsync(() => cut.Find("div").TouchEnd());
        Assert.True(triggered);
    }

    [Fact]
    public void NotImplement_IAsyncDisposable()
    {
        Assert.False(typeof(DynamicElement).GetInterfaces().Any(i => i == typeof(IAsyncDisposable)));
    }
}
